# Rate limiting configuration
MAX_REQUESTS_PER_IP_PER_SECOND = 5
MAX_REQUESTS_PER_IP_PER_MINUTE = 30
RATE_LIMIT_WINDOW_SECONDS = 1
RATE_LIMIT_WINDOW_MINUTES = 60
MAX_RESPONSE_SIZE = 1400  # Keep under typical MTU to avoid fragmentation
CHALLENGE_EXPIRY_SECONDS = 10
CLEANUP_INTERVAL_SECONDS = 30

# Protocol constants
QUERY_TYPE_CHALLENGE_REQUEST = 0x01
QUERY_TYPE_STATUS_REQUEST = 0x02
