class GameState:
    """Holds the current game state. Thread-safe reads via lock."""

    def __init__(self):
        self._lock = threading.Lock()
        self._players: Dict[str, dict] = {}
        self._server_name = "My Game Server"
        self._map_name = "de_dust2"
        self._max_players = 16
        self._game_mode = "deathmatch"

    def add_player(self, player_id: str, name: str, score: int = 0):
        with self._lock:
            self._players[player_id] = {
                "name": name[:32],  # Limit name length
                "score": score,
                "joined_at": time.time()
            }

    def remove_player(self, player_id: str):
        with self._lock:
            self._players.pop(player_id, None)

    def get_status(self, truncate_to_size: int = MAX_RESPONSE_SIZE) -> dict:
        """Return game status, truncating player list if response would be too large."""
        with self._lock:
            status = {
                "name": self._server_name,
                "map": self._map_name,
                "mode": self._game_mode,
                "max_players": self._max_players,
                "num_players": len(self._players),
                "players": []
            }

            # Add players one by one, checking size constraint
            for pid, pdata in self._players.items():
                player_entry = {
                    "id": pid[:16],
                    "name": pdata["name"],
                    "score": pdata["score"]
                }
                status["players"].append(player_entry)

                # Check if serialized size exceeds limit
                # Reserve space for protocol header (8 bytes)
                serialized = json.dumps(status, separators=(',', ':')).encode('utf-8')
                if len(serialized) + 8 > truncate_to_size:
                    # Remove last player and mark as truncated
                    status["players"].pop()
                    status["truncated"] = True
                    break

            return status


class RateLimiter:
    """Per-IP rate limiter to prevent amplification abuse."""

    def __init__(self):
        self._lock = threading.Lock()
        self._entries: Dict[str, RateLimitEntry] = defaultdict(RateLimitEntry)

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self._lock:
            entry = self._entries[ip]

            # Check if IP is temporarily blocked
            if now < entry.blocked_until:
                return False

            # Clean old timestamps
            entry.timestamps = [
                t for t in entry.timestamps
                if now - t < RATE_LIMIT_WINDOW_MINUTES
            ]

            # Check per-minute limit
            if len(entry.timestamps) >= MAX_REQUESTS_PER_IP_PER_MINUTE:
                # Block for escalating duration
                entry.blocked_until = now + 60
                return False

            # Check per-second limit
            recent = [t for t in entry.timestamps if now - t < RATE_LIMIT_WINDOW_SECONDS]
            if len(recent) >= MAX_REQUESTS_PER_IP_PER_SECOND:
                return False

            entry.timestamps.append(now)
            return True

    def cleanup(self):
        """Remove stale entries to prevent memory growth."""
        now = time.time()
        with self._lock:
            stale_ips = [
                ip for ip, entry in self._entries.items()
                if (not entry.timestamps or now - max(entry.timestamps) > RATE_LIMIT_WINDOW_MINUTES * 2)
                and now >= entry.blocked_until
            ]
            for ip in stale_ips:
                del self._entries[ip]


class ChallengeManager:
    """
    Implements challenge-response to prevent IP spoofing amplification attacks.
    
    Clients must first request a challenge token, then include it in their
    status request. This ensures the source IP is real (not spoofed).
    Uses HMAC-based stateless challenges to avoid memory exhaustion.
    """

    def generate_challenge(self, client_ip: str, client_port: int) -> bytes:
        """Generate a stateless challenge token tied to IP, port, and time window."""
        time_window = int(time.time()) // CHALLENGE_EXPIRY_SECONDS
        message = f"{client_ip}:{client_port}:{time_window}".encode()
        token = hmac.new(CHALLENGE_SECRET, message, hashlib.sha256).digest()[:16]
        return token

    def verify_challenge(self, client_ip: str, client_port: int, token: bytes) -> bool:
        """Verify a challenge token. Check current and previous time window."""
        if len(token) != 16:
            return False

        current_window = int(time.time()) // CHALLENGE_EXPIRY_SECONDS

        for window_offset in (0, -1):
            time_window = current_window + window_offset
            message = f"{client_ip}:{client_port}:{time_window}".encode()
            expected = hmac.new(CHALLENGE_SECRET, message, hashlib.sha256).digest()[:16]
            if hmac.compare_digest(token, expected):
                return True

        return False


class GameServer:
    """
    UDP game server with anti-amplification protections:
    
    1. Challenge-response: Clients must prove their IP is real before
       receiving large status responses. This prevents reflected amplification.
    2. Rate limiting: Per-IP request limits prevent abuse.
    3. Response size limiting: Responses are kept small (under MTU) to
       minimize amplification factor.
    4. Input validation: All incoming packets are strictly validated.
    """

    def __init__(self, host: str = "0.0.0.0", port: int = 27015):
        self._host = host
        self._port = port
        self._game_state = GameState()
        self._rate_limiter = RateLimiter()
        self._challenge_manager = ChallengeManager()
        self._running = False
        self._socket: Optional[socket.socket] = None

    def _create_socket(self) -> socket.socket:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        # Set receive buffer to reasonable size
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 65536)
        # Set send buffer - limit to prevent large burst sends
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 65536)
        sock.settimeout(1.0)  # Allow periodic cleanup
        sock.bind((self._host, self._port))
        return sock

    def _build_response(self, response_type: int, payload: bytes) -> bytes:
        """Build a protocol response packet."""
        # Header: version (1 byte) + type (1 byte) + payload length (2 bytes)
        header = struct.pack("!BBH", PROTOCOL_VERSION, response_type, len(payload))
        return header + payload

    def _build_error_response(self, error_msg: str) -> bytes:
        """Build a small error response."""
        payload = error_msg[:64].encode('utf-8')  # Limit error message size
        return self._build_response(RESPONSE_TYPE_ERROR, payload)

    def _handle_challenge_request(self, client_ip: str, client_port: int) -> bytes:
        """
        Handle a challenge request. Returns a small challenge token.
        
        The challenge response is intentionally small (20 bytes header + 16 bytes token)
        to ensure the amplification factor is ~1x even for spoofed IPs.
        """
        token = self._challenge_manager.generate_challenge(client_ip, client_port)
        return self._build_response(RESPONSE_TYPE_CHALLENGE, token)

    def _handle_status_request(self, client_ip: str, client_port: int, data: bytes) -> Optional[bytes]:
        """
        Handle a status request. Requires valid challenge token.
        
        The larger status response is only sent after challenge verification,
        ensuring the client IP is not spoofed.
        """
        # Extract challenge token from request
        # Expected format after header: 16 bytes challenge token
        if len(data) < 16:
            return self._build_error_response("invalid_challenge")

        challenge_token = data[:16]

        if not self._challenge_manager.verify_challenge(client_ip, client_port, challenge_token):
            return self._build_error_response("challenge_failed")

        # Challenge verified - client IP is real, safe to send larger response
        status = self._game_state.get_status(truncate_to_size=MAX_RESPONSE_SIZE)
        payload = json.dumps(status, separators=(',', ':')).encode('utf-8')

        response = self._build_response(RESPONSE_TYPE_STATUS, payload)

        # Final safety check: never exceed max response size
        if len(response) > MAX_RESPONSE_SIZE:
            # This shouldn't happen due to get_status truncation, but be safe
            response = response[:MAX_RESPONSE_SIZE]

        return response

    def _parse_and_handle(self, data: bytes, client_addr: tuple) -> Optional[bytes]:
        """Parse incoming packet and route to appropriate handler."""
        client_ip, client_port = client_addr

        # Validate minimum packet size: version (1) + type (1) = 2 bytes minimum
        if len(data) < 2:
            return None  # Silently drop malformed packets

        # Validate maximum incoming packet size (prevent processing huge packets)
        if len(data) > 256:
            return None  # Silently drop oversized requests

        try:
            version, query_type = struct.unpack("!BB", data[:2])
        except struct.error:
            return None

        # Validate protocol version
        if version != PROTOCOL_VERSION:
            return self._build_error_response("unsupported_version")

        # Rate limit check
        if not self._rate_limiter.is_allowed(client_ip):
            # Don't even send an error response to rate-limited IPs
            # to avoid any amplification
            return None

        payload = data[2:]

        if query_type == QUERY_TYPE_CHALLENGE_REQUEST:
            return self._handle_challenge_request(client_ip, client_port)
        elif query_type == QUERY_TYPE_STATUS_REQUEST:
            return self._handle_status_request(client_ip, client_port, payload)
        else:
            # Unknown query type - small error response
            return self._build_error_response("unknown_query")

    def _cleanup_loop(self):
        """Periodic cleanup of rate limiter entries."""
        while self._running:
            time.sleep(CLEANUP_INTERVAL_SECONDS)
            self._rate_limiter.cleanup()

    def add_player(self, player_id: str, name: str, score: int = 0):
        """Add a player to the game state."""
        self._game_state.add_player(player_id, name, score)

    def remove_player(self, player_id: str):
        """Remove a player from the game state."""
        self._game_state.remove_player(player_id)

    def start(self):
        """Start the game server."""
        self._socket = self._create_socket()
        self._running = True

        # Start cleanup thread
        cleanup_thread = threading.Thread(target=self._cleanup_loop, daemon=True)
        cleanup_thread.start()

        print(f"Game server listening on {self._host}:{self._port}")
        print(f"Anti-amplification protections enabled:")
        print(f"  - Challenge-response required for status queries")
        print(f"  - Rate limit: {MAX_REQUESTS_PER_IP_PER_SECOND}/sec, {MAX_REQUESTS_PER_IP_PER_MINUTE}/min per IP")
        print(f"  - Max response size: {MAX_RESPONSE_SIZE} bytes")

        try:
            while self._running:
                try:
                    data, client_addr = self._socket.recvfrom(512)  # Small receive buffer
                except socket.timeout:
                    continue
                except OSError:
                    if self._running:
                        raise
                    break

                response = self._parse_and_handle(data, client_addr)

                if response is not None:
                    try:
                        self._socket.sendto(response, client_addr)
                    except OSError as e:
                        # Log but don't crash on send errors
                        print(f"Send error to {client_addr[0]}: {e}")
        except KeyboardInterrupt:
            print("\nShutting down...")
        finally:
            self.stop()

    def stop(self):
        """Stop the game server."""
        self._running = False
        if self._socket:
            self._socket.close()
            self._socket = None


def create_test_client(server_host: str = "127.0.0.1", server_port: int = 27015):
    """Example client demonstrating the challenge-response protocol."""
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.settimeout(5.0)
    server_addr = (server_host, server_port)

    try:
        # Step 1: Request a challenge
        challenge_request = struct.pack("!BB", PROTOCOL_VERSION, QUERY_TYPE_CHALLENGE_REQUEST)
        print(f"Sending challenge request ({len(challenge_request)} bytes)...")
        sock.sendto(challenge_request, server_addr)

        response, _ = sock.recvfrom(1500)
        version, resp_type, payload_len = struct.unpack("!BBH", response[:4])
        print(f"Received response: version={version}, type=0x{resp_type:02x}, payload_len={payload_len}")

        if resp_type != RESPONSE_TYPE_CHALLENGE:
            print(f"Unexpected response type: 0x{resp_type:02x}")
            return

        challenge_token = response[4:4 + payload_len]
        print(f"Got challenge token: {challenge_token.hex()}")

        # Step 2: Send status request with challenge token
        status_request = struct.pack("!BB", PROTOCOL_VERSION, QUERY_TYPE_STATUS_REQUEST) + challenge_token
        print(f"\nSending status request with challenge ({len(status_request)} bytes)...")
        sock.sendto(status_request, server_addr)

        response, _ = sock.recvfrom(1500)
        version, resp_type, payload_len = struct.unpack("!BBH", response[:4])
        print(f"Received response: version={version}, type=0x{resp_type:02x}, payload_len={payload_len}")

        if resp_type == RESPONSE_TYPE_STATUS:
            status_json = response[4:4 + payload_len].decode('utf-8')
            status = json.loads(status_json)
            print(f"\nServer Status:")
            print(f"  Name: {status['name']}")
            print(f"  Map: {status['map']}")
            print(f"  Mode: {status['mode']}")
            print(f"  Players: {status['num_players']}/{status['max_players']}")
            for player in status.get('players', []):
                print(f"    - {player['name']} (score: {player['score']})")
            if status.get('truncated'):
                print(f"  (player list truncated)")
        elif resp_type == RESPONSE_TYPE_ERROR:
            error_msg = response[4:4 + payload_len].decode('utf-8')
            print(f"Error: {error_msg}")

        # Step 3: Demonstrate that a request without valid challenge fails
        print("\n--- Testing without valid challenge ---")
        fake_token = b'\x00' * 16
        bad_request = struct.pack("!BB", PROTOCOL_VERSION, QUERY_TYPE_STATUS_REQUEST) + fake_token
        sock.sendto(bad_request, server_addr)

        response, _ = sock.recvfrom(1500)
        version, resp_type, payload_len = struct.unpack("!BBH", response[:4])
        if resp_type == RESPONSE_TYPE_ERROR:
            error_msg = response[4:4 + payload_len].decode('utf-8')
            print(f"Expected error received: {error_msg}")

    except socket.timeout:
        print("Request timed out")
    finally:
        sock.close()


